    int m_id{};
    A(int id) : m_id{id} {}
};

// Build a virtual-inheritance diamond. B and C each try to initialize A and
// keep their own tag; D is the most-derived class and initializes A directly.

int main()
{
    int bId{}, cId{}, dId{}, bTag{}, cTag{};
    std::cin >> bId >> cId >> dId >> bTag >> cTag;

    // Build one D and report the shared A id plus each intermediate's tag.

    return 0;
}

solution_code:
#include <iostream>

class A
{
public:
    int m_id{};
    A(int id) : m_id{id} {}
};

class B : virtual public A
{
public:
    int m_tag{};
    B(int aId, int tag) : A{aId}, m_tag{tag} {}
};

class C : virtual public A
{
public:
    int m_tag{};
    C(int aId, int tag) : A{aId}, m_tag{tag} {}
};

class D : public B, public C
{
public:
    D(int bId, int cId, int dId, int bTag, int cTag)
        : A{dId}, B{bId, bTag}, C{cId, cTag} {}
    void show() const
    {
        std::cout << "A id: " << m_id << '\n';
        std::cout << "B tag: " << B::m_tag << '\n';
        std::cout << "C tag: " << C::m_tag << '\n';
    }
};

int main()
{
    int bId{}, cId{}, dId{}, bTag{}, cTag{};
    std::cin >> bId >> cId >> dId >> bTag >> cTag;

    D d{bId, cId, dId, bTag, cTag};
    d.show();
    return 0;
}
